class Solution {
    public int racecar(int target) {
        int[][] dp = new int[target + 1][2];
        for (int i = 0; i <= target; i++) {
            dp[i][0] = dp[i][1] = Integer.MAX_VALUE;
        }
        dp[0][0] = 0;
        for (int i = 1; i <= target; i++) {
            int pos = 0, speed = 1;
            int steps = 0;
            while (pos < i) {
                pos += speed;
                speed *= 2;
                steps++;
            }
            if (pos == i) {
                dp[i][0] = Math.min(dp[i][0], steps);
            } else {
                dp[i][0] = Math.min(dp[i][0], steps + 1 + dp[pos - i][1]);
            }
            pos = 0;
            speed = -1;
            steps = 1;
            while (pos > -i) {
                pos += speed;
                speed *= 2;
                steps++;
            }
            if (pos == -i) {
                dp[i][1] = Math.min(dp[i][1], steps);
            } else {
                dp[i][1] = Math.min(dp[i][1], steps + 1 + dp[i - pos][0]);
            }
        }
        return Math.min(dp[target][0], dp[target][1]);
    }
}
